#include "GardenDeviceFramework.h"
namespace Garden {
GardenDeviceBase::GardenDeviceBase(const GardenDeviceOptions& options) : _options(options), _server(options.localPort) { _deviceType=options.deviceType?options.deviceType:"garden-device"; _devicePrefix=options.devicePrefix?options.devicePrefix:"GardenDevice"; _firmwareVersion=options.firmwareVersion?options.firmwareVersion:"dev"; }
void GardenDeviceBase::begin(){ Serial.begin(115200); delay(50); loadBaseConfig(); ensureDeviceIdentity(); WiFi.persistent(false); WiFi.mode(WIFI_AP_STA); startLocalAp(); connectToMasterWifi(false); setupBaseRoutes(); onDeviceBegin(); _server.begin(); enqueueSimpleEvent("device.booted"); }
void GardenDeviceBase::loop(){ _server.handleClient(); if(WiFi.status()!=WL_CONNECTED){ uint32_t now=millis(); if(now-_lastOfflineRetryMs>_options.offlineRetryIntervalMs){ _lastOfflineRetryMs=now; connectToMasterWifi(false);} } syncWithMaster(); onDeviceLoop(); }
void GardenDeviceBase::ensureDeviceIdentity(){ if(_deviceId.length()==0)_deviceId=generateDeviceId(); if(_localApSsid.length()==0)_localApSsid=defaultLocalApSsidForId(_deviceId); if(_localApPassword.length()==0)_localApPassword=_options.defaultLocalApPassword?_options.defaultLocalApPassword:"admin"; if(_adminPassword.length()==0)_adminPassword=_options.defaultAdminPassword?_options.defaultAdminPassword:"admin"; saveBaseConfig(); }
String GardenDeviceBase::generateDeviceId(){ uint64_t mac=ESP.getEfuseMac(); char suffix[17]; snprintf(suffix,sizeof(suffix),"%04X%08X",(uint16_t)(mac>>32),(uint32_t)mac); String n=_deviceType; n.toLowerCase(); n.replace("_","-"); n.replace(" ","-"); return n+"-"+String(suffix); }
String GardenDeviceBase::defaultLocalApSsidForId(const String& id){ return _devicePrefix+"-"+id; }
void GardenDeviceBase::loadBaseConfig(){ _prefs.begin("gdf",true); _deviceId=_prefs.getString("deviceId",""); _localApSsid=_prefs.getString("apSsid",""); _localApPassword=_prefs.getString("apPass",_options.defaultLocalApPassword?_options.defaultLocalApPassword:"admin"); _adminPassword=_prefs.getString("adminPass",_options.defaultAdminPassword?_options.defaultAdminPassword:"admin"); _masterSsid=_prefs.getString("masterSsid",_options.defaultMasterSsid?_options.defaultMasterSsid:""); _masterPassword=_prefs.getString("masterPass",_options.defaultMasterPassword?_options.defaultMasterPassword:""); _masterBaseUrl=_prefs.getString("masterUrl",_options.defaultMasterBaseUrl?_options.defaultMasterBaseUrl:"http://garden-master.local"); _serverBaseUrl=_prefs.getString("serverUrl",_options.defaultServerBaseUrl?_options.defaultServerBaseUrl:""); _apiToken=_prefs.getString("apiToken",_options.defaultApiToken?_options.defaultApiToken:""); _configVersion=_prefs.getUInt("cfgVer",1); _configHash=_prefs.getString("cfgHash",""); _dirtyLocalConfig=_prefs.getBool("dirty",false); _dirtyReason=_prefs.getString("dirtyReason",""); _prefs.end(); }
void GardenDeviceBase::saveBaseConfig(){ _prefs.begin("gdf",false); _prefs.putString("deviceId",_deviceId); _prefs.putString("apSsid",_localApSsid); _prefs.putString("apPass",_localApPassword); _prefs.putString("adminPass",_adminPassword); _prefs.putString("masterSsid",_masterSsid); _prefs.putString("masterPass",_masterPassword); _prefs.putString("masterUrl",_masterBaseUrl); _prefs.putString("serverUrl",_serverBaseUrl); _prefs.putString("apiToken",_apiToken); _prefs.putUInt("cfgVer",_configVersion); _prefs.putString("cfgHash",_configHash); _prefs.putBool("dirty",_dirtyLocalConfig); _prefs.putString("dirtyReason",_dirtyReason); _prefs.end(); }
void GardenDeviceBase::factoryResetBase(){ onBeforeFactoryReset(); _prefs.begin("gdf",false); _prefs.clear(); _prefs.end(); _deviceId=""; _localApSsid=""; _localApPassword=_options.defaultLocalApPassword?_options.defaultLocalApPassword:"admin"; _adminPassword=_options.defaultAdminPassword?_options.defaultAdminPassword:"admin"; _masterSsid=_options.defaultMasterSsid?_options.defaultMasterSsid:""; _masterPassword=_options.defaultMasterPassword?_options.defaultMasterPassword:""; _masterBaseUrl=_options.defaultMasterBaseUrl?_options.defaultMasterBaseUrl:"http://garden-master.local"; _serverBaseUrl=_options.defaultServerBaseUrl?_options.defaultServerBaseUrl:""; _apiToken=_options.defaultApiToken?_options.defaultApiToken:""; _configVersion=1; _configHash=""; _dirtyLocalConfig=false; _dirtyReason=""; ensureDeviceIdentity(); }
void GardenDeviceBase::startLocalAp(){ if(_localApPassword.length()>0 && _localApPassword.length()<8) WiFi.softAP(_localApSsid.c_str()); else WiFi.softAP(_localApSsid.c_str(),_localApPassword.c_str()); }
void GardenDeviceBase::restartLocalAp(){ WiFi.softAPdisconnect(true); delay(100); startLocalAp(); }
void GardenDeviceBase::connectToMasterWifi(bool wait){ if(_masterSsid.length()==0){ setSyncStatus(SyncStatus::Offline); return;} WiFi.begin(_masterSsid.c_str(),_masterPassword.c_str()); if(wait){ uint32_t start=millis(); while(WiFi.status()!=WL_CONNECTED && millis()-start<15000UL) delay(250);} setSyncStatus(WiFi.status()==WL_CONNECTED?SyncStatus::Online:SyncStatus::Offline); }
void GardenDeviceBase::setupBaseRoutes(){ _server.on("/",HTTP_GET,[this](){handleRoot();}); _server.on("/api/state",HTTP_GET,[this](){handleState();}); _server.on("/api/config",HTTP_GET,[this](){handleConfigGet();}); _server.on("/api/config",HTTP_POST,[this](){handleConfigPost();}); _server.on("/api/network",HTTP_POST,[this](){handleNetworkPost();}); _server.on("/api/factory-reset",HTTP_POST,[this](){handleFactoryReset();}); _server.on("/api/sync/push",HTTP_POST,[this](){handlePushNow();}); _server.on("/api/sync/pull",HTTP_POST,[this](){handlePullNow();}); }
bool GardenDeviceBase::requireLocalAdmin(){ return true; }
void GardenDeviceBase::handleRoot(){ _server.send(200,"text/html",localAdminHtml()); }
void GardenDeviceBase::handleState(){ JsonDocument doc; buildStateJson(doc); sendJson(200,doc); }
void GardenDeviceBase::handleConfigGet(){ JsonDocument doc; doc["deviceId"]=_deviceId; doc["deviceType"]=_deviceType; doc["firmwareVersion"]=_firmwareVersion; doc["configVersion"]=_configVersion; doc["configHash"]=_configHash; doc["dirtyLocalConfig"]=_dirtyLocalConfig; doc["dirtyReason"]=_dirtyReason; JsonObject network=doc["network"].to<JsonObject>(); network["localApSsid"]=_localApSsid; network["localApPasswordIsDefault"]=_localApPassword=="admin"; network["masterSsid"]=_masterSsid; network["masterBaseUrl"]=_masterBaseUrl; network["serverBaseUrl"]=_serverBaseUrl; JsonObject dc=doc["deviceConfig"].to<JsonObject>(); appendDeviceConfig(dc); sendJson(200,doc); }
void GardenDeviceBase::handleConfigPost(){ if(!requireLocalAdmin())return; JsonDocument doc; if(deserializeJson(doc,_server.arg("plain"))){sendError(400,"Invalid JSON");return;} bool ok=applyDeviceConfig(doc.as<JsonObjectConst>()); if(!ok){sendError(400,"Device rejected config");return;} markLocalConfigDirty("local-admin"); saveBaseConfig(); sendOk(); }
void GardenDeviceBase::handleNetworkPost(){ if(!requireLocalAdmin())return; JsonDocument doc; if(deserializeJson(doc,_server.arg("plain"))){sendError(400,"Invalid JSON");return;} if(doc["localApSsid"].is<const char*>())_localApSsid=(const char*)doc["localApSsid"]; if(doc["localApPassword"].is<const char*>())_localApPassword=(const char*)doc["localApPassword"]; if(doc["adminPassword"].is<const char*>())_adminPassword=(const char*)doc["adminPassword"]; if(doc["masterSsid"].is<const char*>())_masterSsid=(const char*)doc["masterSsid"]; if(doc["masterPassword"].is<const char*>())_masterPassword=(const char*)doc["masterPassword"]; if(doc["masterBaseUrl"].is<const char*>())_masterBaseUrl=(const char*)doc["masterBaseUrl"]; if(doc["serverBaseUrl"].is<const char*>())_serverBaseUrl=(const char*)doc["serverBaseUrl"]; if(doc["apiToken"].is<const char*>())_apiToken=(const char*)doc["apiToken"]; markLocalConfigDirty("local-network-admin"); saveBaseConfig(); restartLocalAp(); connectToMasterWifi(false); sendOk(); }
void GardenDeviceBase::handleFactoryReset(){ if(!requireLocalAdmin())return; factoryResetBase(); sendOk(); delay(500); ESP.restart(); }
void GardenDeviceBase::handlePushNow(){ pushDirtyConfigToMaster(); sendOk(); }
void GardenDeviceBase::handlePullNow(){ pollMasterMessages(); sendOk(); }
void GardenDeviceBase::buildStateJson(JsonDocument& doc){ doc["deviceId"]=_deviceId; doc["deviceType"]=_deviceType; doc["firmwareVersion"]=_firmwareVersion; doc["configVersion"]=_configVersion; doc["configHash"]=_configHash; doc["dirtyLocalConfig"]=_dirtyLocalConfig; doc["dirtyReason"]=_dirtyReason; doc["syncStatus"]=syncStatusString(); doc["lastSyncMessage"]=_lastSyncMessage; doc["uptimeSeconds"]=millis()/1000UL; JsonObject network=doc["network"].to<JsonObject>(); network["localApSsid"]=_localApSsid; network["localApIp"]=WiFi.softAPIP().toString(); network["masterWifiConnected"]=WiFi.status()==WL_CONNECTED; network["masterWifiSsid"]=_masterSsid; network["masterIp"]=WiFi.localIP().toString(); network["rssi"]=WiFi.status()==WL_CONNECTED?WiFi.RSSI():0; network["masterBaseUrl"]=_masterBaseUrl; network["localApPasswordIsDefault"]=_localApPassword=="admin"; JsonArray caps=doc["capabilities"].to<JsonArray>(); appendCapabilities(caps); JsonObject state=doc["deviceState"].to<JsonObject>(); appendDeviceState(state); }
String GardenDeviceBase::buildStateJsonString(){ JsonDocument doc; buildStateJson(doc); String out; serializeJson(doc,out); return out; }
void GardenDeviceBase::sendJson(int code,JsonDocument& doc){ String out; serializeJson(doc,out); _server.send(code,"application/json",out); }
void GardenDeviceBase::sendOk(){ JsonDocument doc; doc["ok"]=true; sendJson(200,doc); }
void GardenDeviceBase::sendError(int code,const char* message){ JsonDocument doc; doc["ok"]=false; doc["error"]=message; sendJson(code,doc); }
void GardenDeviceBase::markLocalConfigDirty(const char* reason){ _dirtyLocalConfig=true; _dirtyReason=reason?reason:"local-change"; _configVersion++; _configHash=computeConfigHash(); saveBaseConfig(); setSyncStatus(SyncStatus::DirtyLocal); }
void GardenDeviceBase::markConfigClean(uint32_t appliedVersion,const String& appliedHash){ _configVersion=appliedVersion; _configHash=appliedHash; _dirtyLocalConfig=false; _dirtyReason=""; saveBaseConfig(); setSyncStatus(SyncStatus::InSync); }
bool GardenDeviceBase::enqueueSimpleEvent(const char* type){ JsonDocument doc; JsonObject payload=doc["payload"].to<JsonObject>(); payload["note"]=""; return enqueueEvent(type,payload); }
bool GardenDeviceBase::enqueueEvent(const char* type,JsonObjectConst payload){ String payloadJson; serializeJson(payload,payloadJson); return enqueueEvent(type,payloadJson); }
bool GardenDeviceBase::enqueueEvent(const char* type,const String& payloadJson){ for(uint8_t i=0;i<GDF_EVENT_OUTBOX_SIZE;i++){ if(!_outbox[i].used){ _outbox[i].used=true; _outbox[i].id=makeEventId(); _outbox[i].type=type?type:"event.unknown"; _outbox[i].payloadJson=payloadJson; _outbox[i].createdAt=millis()/1000UL; return true; }} return false; }
String GardenDeviceBase::makeEventId(){ _eventSeq++; return _deviceId+"-"+String(millis())+"-"+String(_eventSeq); }
void GardenDeviceBase::syncWithMaster(){ uint32_t now=millis(); if(WiFi.status()!=WL_CONNECTED){ setSyncStatus(_dirtyLocalConfig?SyncStatus::DirtyLocal:SyncStatus::Offline); return;} if(_dirtyLocalConfig && now-_lastEventFlushMs>_options.eventFlushIntervalMs){ _lastEventFlushMs=now; pushDirtyConfigToMaster(); } if(now-_lastHeartbeatMs>_options.heartbeatIntervalMs){ _lastHeartbeatMs=now; sendHeartbeat(); } if(now-_lastEventFlushMs>_options.eventFlushIntervalMs){ _lastEventFlushMs=now; flushEvents(); } if(now-_lastMasterPollMs>1000UL){ _lastMasterPollMs=now; pollMasterMessages(); } }
void GardenDeviceBase::sendHeartbeat(){ if(_masterBaseUrl.length()==0)return; JsonDocument doc; buildStateJson(doc); String body,response; int code=0; serializeJson(doc,body); String path="/api/master/devices/"+_deviceId+"/heartbeat"; if(postJson(_masterBaseUrl,path,body,response,code)){ _lastSyncMessage="heartbeat ok"; if(!_dirtyLocalConfig)setSyncStatus(SyncStatus::Online);} else { _lastSyncMessage="heartbeat failed "+String(code); setSyncStatus(_dirtyLocalConfig?SyncStatus::DirtyLocal:SyncStatus::Error);} }
void GardenDeviceBase::pollMasterMessages(){ if(_masterBaseUrl.length()==0||WiFi.status()!=WL_CONNECTED)return; String response; int code=0; String path="/api/master/devices/"+_deviceId+"/messages/next?wait="+String(_options.masterPollWaitSeconds); bool ok=getJson(_masterBaseUrl,path,response,code); if(code==204)return; if(!ok||response.length()==0)return; JsonDocument doc; if(deserializeJson(doc,response)||!doc["message"].is<JsonObject>()){_lastSyncMessage="message parse failed";return;} JsonObjectConst msg=doc["message"].as<JsonObjectConst>(); bool applied=applyMessage(msg); JsonDocument ack; ack["status"]=applied?"applied":"failed"; String ackBody,ackResp; int ackCode=0; serializeJson(ack,ackBody); String id=msg["id"]|""; if(id.length()) postJson(_masterBaseUrl,"/api/master/messages/"+id+"/ack",ackBody,ackResp,ackCode); }
void GardenDeviceBase::flushEvents(){ if(_masterBaseUrl.length()==0||WiFi.status()!=WL_CONNECTED)return; for(uint8_t i=0;i<GDF_EVENT_OUTBOX_SIZE;i++){ if(!_outbox[i].used)continue; JsonDocument doc; doc["id"]=_outbox[i].id; doc["type"]=_outbox[i].type; doc["source"]=_deviceId; doc["deviceType"]=_deviceType; doc["createdAt"]=_outbox[i].createdAt; doc["configVersion"]=_configVersion; JsonDocument payloadDoc; if(!deserializeJson(payloadDoc,_outbox[i].payloadJson)) doc["payload"]=payloadDoc.as<JsonVariantConst>(); else doc["payloadRaw"]=_outbox[i].payloadJson; String body,response; int code=0; serializeJson(doc,body); if(postJson(_masterBaseUrl,"/api/master/devices/"+_deviceId+"/events",body,response,code)) _outbox[i].used=false; else return; }}
void GardenDeviceBase::pushDirtyConfigToMaster(){ if(!_dirtyLocalConfig||_masterBaseUrl.length()==0||WiFi.status()!=WL_CONNECTED)return; JsonDocument doc; doc["type"]="device.config.changed_locally"; doc["source"]=_deviceId; doc["deviceId"]=_deviceId; doc["deviceType"]=_deviceType; doc["configVersion"]=_configVersion; doc["configHash"]=_configHash; doc["dirtyReason"]=_dirtyReason; JsonObject config=doc["config"].to<JsonObject>(); config["deviceId"]=_deviceId; config["deviceType"]=_deviceType; config["firmwareVersion"]=_firmwareVersion; config["localApSsid"]=_localApSsid; config["masterSsid"]=_masterSsid; config["masterBaseUrl"]=_masterBaseUrl; appendDeviceConfig(config); String body,response; int code=0; serializeJson(doc,body); String path="/api/master/devices/"+_deviceId+"/config/local-change"; if(postJson(_masterBaseUrl,path,body,response,code)){ _dirtyLocalConfig=false; _dirtyReason=""; saveBaseConfig(); setSyncStatus(SyncStatus::InSync); _lastSyncMessage="local config pushed"; } else { _lastSyncMessage="config push failed "+String(code); setSyncStatus(SyncStatus::DirtyLocal); }}
bool GardenDeviceBase::applyMessage(JsonObjectConst message){ String type=message["type"]|""; JsonObjectConst payload=message["payload"].is<JsonObjectConst>()?message["payload"].as<JsonObjectConst>():message; if(type=="config.bundle.replace") return applyConfigBundle(payload); return handleDeviceMessage(type,message,payload); }
bool GardenDeviceBase::applyConfigBundle(JsonObjectConst payload){ uint32_t incomingVersion=payload["configVersion"]|0; String incomingHash=payload["configHash"]|""; if(!validateIncomingConfigVersion(incomingVersion,incomingHash)){ setSyncStatus(SyncStatus::Conflict); enqueueSimpleEvent("config.rejected"); return false;} if(payload["network"].is<JsonObjectConst>()){ JsonObjectConst n=payload["network"].as<JsonObjectConst>(); if(n["masterSsid"].is<const char*>())_masterSsid=(const char*)n["masterSsid"]; if(n["masterPassword"].is<const char*>())_masterPassword=(const char*)n["masterPassword"]; if(n["masterBaseUrl"].is<const char*>())_masterBaseUrl=(const char*)n["masterBaseUrl"]; } bool ok=true; if(payload["deviceConfig"].is<JsonObjectConst>()) ok=applyDeviceConfig(payload["deviceConfig"].as<JsonObjectConst>()); if(ok){ _configVersion=incomingVersion>0?incomingVersion:_configVersion+1; _configHash=incomingHash.length()?incomingHash:computeConfigHash(); _dirtyLocalConfig=false; _dirtyReason=""; saveBaseConfig(); onAfterConfigApplied(); enqueueSimpleEvent("config.applied"); setSyncStatus(SyncStatus::InSync);} return ok; }
bool GardenDeviceBase::validateIncomingConfigVersion(uint32_t incomingVersion,const String& incomingHash){ if(_dirtyLocalConfig)return false; if(incomingVersion==0)return true; if(incomingVersion>_configVersion)return true; if(incomingVersion==_configVersion&&(incomingHash.length()==0||incomingHash==_configHash))return true; return false; }
bool GardenDeviceBase::httpBeginUrl(HTTPClient& http,WiFiClient& plain,WiFiClientSecure& secure,const String& url){ if(url.startsWith("https://")){ if(_options.useHttpsInsecure)secure.setInsecure(); return http.begin(secure,url);} return http.begin(plain,url); }
void GardenDeviceBase::addAuthHeaders(HTTPClient& http){ http.addHeader("Content-Type","application/json"); if(_apiToken.length()>0)http.addHeader("x-api-token",_apiToken); if(_deviceId.length()>0)http.addHeader("x-device-id",_deviceId); }
bool GardenDeviceBase::postJson(const String& baseUrl,const String& path,const String& body,String& response,int& code){ response=""; code=-999; WiFiClient plain; WiFiClientSecure secure; HTTPClient http; String url=baseUrl; while(url.endsWith("/"))url.remove(url.length()-1); url+=path; if(!httpBeginUrl(http,plain,secure,url))return false; addAuthHeaders(http); http.setTimeout(10000); code=http.POST(body); if(code>0)response=http.getString(); http.end(); return code>=200&&code<300; }
bool GardenDeviceBase::getJson(const String& baseUrl,const String& path,String& response,int& code){ response=""; code=-999; WiFiClient plain; WiFiClientSecure secure; HTTPClient http; String url=baseUrl; while(url.endsWith("/"))url.remove(url.length()-1); url+=path; if(!httpBeginUrl(http,plain,secure,url))return false; addAuthHeaders(http); http.setTimeout((_options.masterPollWaitSeconds+5)*1000UL); code=http.GET(); if(code>0)response=http.getString(); http.end(); return code>=200&&code<300; }
String GardenDeviceBase::computeConfigHash(){ JsonDocument doc; doc["deviceId"]=_deviceId; doc["deviceType"]=_deviceType; doc["configVersion"]=_configVersion; doc["localApSsid"]=_localApSsid; doc["masterSsid"]=_masterSsid; doc["masterBaseUrl"]=_masterBaseUrl; JsonObject cfg=doc["deviceConfig"].to<JsonObject>(); appendDeviceConfig(cfg); String s; serializeJson(doc,s); uint32_t h=fnv1a(s); char buf[16]; snprintf(buf,sizeof(buf),"fnv1a-%08lx",(unsigned long)h); return String(buf); }
uint32_t GardenDeviceBase::fnv1a(const String& text){ uint32_t hash=2166136261UL; for(size_t i=0;i<text.length();i++){ hash^=(uint8_t)text[i]; hash*=16777619UL;} return hash; }
void GardenDeviceBase::setSyncStatus(SyncStatus status){ if(_syncStatus==status)return; _syncStatus=status; onSyncStatusChanged(status); }
const char* GardenDeviceBase::syncStatusString() const{ switch(_syncStatus){ case SyncStatus::Offline:return "offline"; case SyncStatus::Online:return "online"; case SyncStatus::InSync:return "in_sync"; case SyncStatus::DirtyLocal:return "dirty_local"; case SyncStatus::Conflict:return "conflict"; case SyncStatus::Error:return "error"; default:return "unknown"; }}
String GardenDeviceBase::htmlEscape(const String& s){ String out; for(size_t i=0;i<s.length();i++){ char c=s[i]; if(c=='&')out+="&amp;"; else if(c=='<')out+="&lt;"; else if(c=='>')out+="&gt;"; else if(c=='\"')out+="&quot;"; else out+=c;} return out; }
String GardenDeviceBase::localAdminHtml(){ String h; h+="<!doctype html><html><head><meta name='viewport' content='width=device-width,initial-scale=1'><title>"+htmlEscape(_deviceId)+"</title><style>body{font-family:Arial;margin:0;background:#f5f2e8;color:#111}header{background:#203b2a;color:#fff;padding:14px}main{padding:14px;display:grid;gap:12px}.card{background:white;border:1px solid #222;border-radius:12px;padding:12px}code,pre{background:#eee;padding:3px;border-radius:4px}button{font-size:16px;padding:10px;margin:4px}textarea{width:100%;min-height:180px}</style></head><body><header><h1>"+htmlEscape(_devicePrefix)+"</h1><div>"+htmlEscape(_deviceId)+"</div></header><main>"; h+="<section class='card'><h2>Status</h2><pre id='state'>Loading...</pre><button onclick='loadState()'>Refresh</button><button onclick='fetch(\"/api/sync/push\",{method:\"POST\"}).then(loadState)'>Push Local Changes</button></section>"; h+="<section class='card'><h2>Network JSON</h2><textarea id='net'>{\"masterSsid\":\"\",\"masterPassword\":\"\",\"masterBaseUrl\":\"http://garden-master.local\",\"localApPassword\":\"admin\"}</textarea><br><button onclick='postNet()'>Save Network</button></section>"; h+="<section class='card'><h2>Device Config JSON</h2><textarea id='cfg'>{}</textarea><br><button onclick='postCfg()'>Save Device Config</button></section>"; h+="<section class='card'><h2>Factory Reset</h2><button onclick='if(confirm(\"Factory reset this device?\"))fetch(\"/api/factory-reset\",{method:\"POST\"})'>Factory Reset</button></section>"; h+="</main><script>async function loadState(){let r=await fetch('/api/state');state.textContent=JSON.stringify(await r.json(),null,2)}async function postNet(){await fetch('/api/network',{method:'POST',headers:{'Content-Type':'application/json'},body:net.value});loadState()}async function postCfg(){await fetch('/api/config',{method:'POST',headers:{'Content-Type':'application/json'},body:cfg.value});loadState()}loadState();setInterval(loadState,5000);</script></body></html>"; return h; }
} // namespace Garden
